// Flatten Shopify orders into BigQuery raw.ec_shopify_orders rows.
// Identical transformation to the initial backfill workflow.

const rows = [];
const now = new Date().toISOString();

const toIntYen = (v) => {
  if (v === null || v === undefined || v === '') return null;
  return Math.round(parseFloat(v));
};
const toDate = (iso) => (iso ? iso.split('T')[0] : null);
const toStr = (v) => (v === null || v === undefined ? null : String(v));

for (const item of $input.all()) {
  const o = item.json;

  let utm_source = null, utm_medium = null, utm_campaign = null;
  if (o.landing_site) {
    try {
      const url = new URL(o.landing_site, 'https://placeholder.invalid');
      utm_source = url.searchParams.get('utm_source');
      utm_medium = url.searchParams.get('utm_medium');
      utm_campaign = url.searchParams.get('utm_campaign');
    } catch (e) {}
  }

  const firstRefund = (o.refunds && o.refunds.length > 0) ? o.refunds[0] : null;
  const is_refunded = firstRefund !== null;
  const refund_date = firstRefund ? toDate(firstRefund.created_at) : null;
  const refund_amount = firstRefund
    ? toIntYen((firstRefund.transactions || []).reduce((s, t) => s + parseFloat(t.amount || '0'), 0))
    : null;
  const refund_reason = firstRefund ? (firstRefund.note || null) : null;

  const customer_email = (o.customer && o.customer.email) || o.email || null;
  if (!customer_email) continue;

  for (const li of (o.line_items || [])) {
    const lineDiscount = (li.discount_allocations || [])
      .reduce((s, d) => s + parseFloat(d.amount || '0'), 0);
    rows.push({
      order_id: toStr(o.id),
      order_name: o.name || null,
      created_at: o.created_at,
      order_date: toDate(o.created_at),
      customer_id: o.customer ? toStr(o.customer.id) : null,
      customer_email: customer_email,
      financial_status: o.financial_status || null,
      total_price: toIntYen(o.total_price),
      subtotal_price: toIntYen(o.subtotal_price),
      total_discounts: toIntYen(o.total_discounts),
      total_tax: toIntYen(o.total_tax),
      line_item_id: toStr(li.id),
      product_id: li.product_id ? toStr(li.product_id) : null,
      variant_id: li.variant_id ? toStr(li.variant_id) : null,
      sku: li.sku || '',
      sku_title: li.title || null,
      variant_title: li.variant_title || null,
      quantity: li.quantity,
      unit_price: toIntYen(li.price),
      line_discount: lineDiscount > 0 ? toIntYen(lineDiscount) : null,
      is_refunded: is_refunded,
      refund_date: refund_date,
      refund_amount: refund_amount,
      refund_reason: refund_reason,
      source_name: o.source_name || null,
      landing_site: o.landing_site || null,
      referring_site: o.referring_site || null,
      utm_source: utm_source,
      utm_medium: utm_medium,
      utm_campaign: utm_campaign,
      tags: o.tags || null,
      inserted_at: now
    });
  }
}

return rows.map((json) => ({ json }));
